mapper.update:
INSERT INTO TB_SYS_MENU (
      SYS_MENU_CD
    , UPR_MENU_CD
    , MENU_NM
    , MENU_LVL
    , MENU_SORT
    , MENU_URL
    , MENU_SYS_DIV
    , MENU_DIV
    , BRD_CD
    , USE_YN
    , BIGO
    , CRE_USR_CD
    , CRE_DTM
    , UPD_USR_CD
    , UPD_DTM
    , DEL_YN
)
VALUES

    (
          #{rm.sysMenuCd}
        , #{rm.uprMenuCd}
        , #{rm.menuNm}
        , #{rm.menuLvl}
        , #{rm.menuSort} 
        , #{rm.menuUrl}
        , #{rm.menuSysDiv}
        , #{rm.menuDiv}
        , #{rm.brdCd}
        , #{rm.useYn}
        , #{rm.bigo}
        , #{ssnUsrCd}
        , SYSDATE()
        , #{ssnUsrCd}
        , SYSDATE()
        , 'N'
    )

ON DUPLICATE KEY UPDATE
      MENU_NM              = VALUES(MENU_NM)
    , MENU_SORT            = VALUES(MENU_SORT)
    , MENU_URL             = VALUES(MENU_URL)
    , BRD_CD               = VALUES(BRD_CD)
    , BIGO                 = VALUES(BIGO)
    , USE_YN               = VALUES(USE_YN)
    , UPD_USR_CD           = #{ssnUsrCd}
    , UPD_DTM              = SYSDATE()
    , DEL_YN               = 'N'

